# Run test
RESPONSE=$(echo "$REQUEST" | ./target/debug/examples/icons_test_server 2>>"$LOG_FILE")
log "DEBUG" "Response: $RESPONSE"

# Verify icon present
if echo "$RESPONSE" | jq -e '.result.tools[] | select(.icon != null)' > /dev/null 2>&1; then
    log "INFO" "PASS: Icons present in tools list"
else
    log "ERROR" "FAIL: No icons found in response"
    exit 1
fi

# Verify icon structure
ICON=$(echo "$RESPONSE" | jq -r '.result.tools[0].icon')
log "DEBUG" "Icon structure: $ICON"

if echo "$ICON" | jq -e '.src' > /dev/null 2>&1; then
    log "INFO" "PASS: Icon has src field"
else
    log "ERROR" "FAIL: Icon missing src field"
    exit 1
fi

# Test no icon when not set
if echo "$RESPONSE" | jq -e '.result.tools[] | select(.name == "no_icon_tool") | .icon == null' > /dev/null 2>&1; then
    log "INFO" "PASS: No icon field when not set"
else
    log "ERROR" "FAIL: Icon field present when should be absent"
    exit 1
fi

